 1	import * as React from 'react';
 2	import { connect } from 'react-redux';
 3	import { pluralize } from '@patternfly/react-core';
 4	import { ChartCursorFlyout, ChartLabelProps } from '@patternfly/react-charts';
 5	import { kialiStyle } from 'styles/StyleUtils';
 6	import { KialiAppState } from 'store/Store';
 7	import { averageSpanDuration, reduceMetricsStats, StatsMatrix } from 'utils/tracing/TraceStats';
 8	import { JaegerLineInfo } from './TracingScatter';
 9	import { JaegerTrace } from 'types/TracingInfo';
10	import { renderTraceHeatMap } from './TracingResults/StatsComparison';
11	import { PFColors } from 'components/Pf/PfColors';
12	import { HookedChartTooltip, HookedTooltipProps } from 'components/Charts/CustomTooltip';
13	import { formatDuration } from 'utils/tracing/TracingHelper';
14	
15	const flyoutWidth = 280;
16	const flyoutHeight = 130;
17	const flyoutMargin = 10;
18	const innerWidth = flyoutWidth - 2 * flyoutMargin;
19	const innerHeight = flyoutHeight - 2 * flyoutMargin;
20	
21	const tooltipStyle = kialiStyle({
22	  color: PFColors.ColorLight100,
23	  width: innerWidth,
24	  height: innerHeight
25	});
26	
27	const titleStyle = kialiStyle({
28	  whiteSpace: 'nowrap',
29	  overflow: 'hidden',
30	  textOverflow: 'ellipsis'
31	});
32	
33	const contentStyle = kialiStyle({ width: '100%', height: '100%' });
34	const leftStyle = kialiStyle({ width: '35%', height: '100%', float: 'left' });
35	
36	type LabelProps = ChartLabelProps & {
37	  isStatsMatrixComplete: boolean;
38	  provider?: string;
39	  trace: JaegerTrace;
40	  statsMatrix?: StatsMatrix;
41	};
42	
43	class TraceLabel extends React.Component<LabelProps> {
44	  render() {
45	    const left = flyoutMargin + (this.props.x || 0) - flyoutWidth / 2;
46	    const top = flyoutMargin + (this.props.y || 0) - flyoutHeight / 2;
47	    const avgSpanDuration = averageSpanDuration(this.props.trace);
48	    const hasStats = this.props.statsMatrix && this.props.statsMatrix.some(sub => sub.some(v => v !== undefined));
49	
50	    return (
51	      <foreignObject width={innerWidth} height={innerHeight} x={left} y={top}>
52	        <div className={tooltipStyle}>
53	          <div className={titleStyle}>{this.props.trace.traceName || '(Missing root span)'}</div>
54	          <br />
55	          <div className={contentStyle}>
56	            <div className={leftStyle}>{hasStats ? renderTraceHeatMap(this.props.statsMatrix!, true) : 'n/a'}</div>
57	            <div>
58	              {formatDuration(this.props.trace.duration)}
59	              <br />
60	              {`${pluralize(this.props.trace.spans.length, 'span')}, avg=${
61	                avgSpanDuration ? formatDuration(avgSpanDuration) : 'n/a'
62	              }`}
63	            </div>
64	          </div>
65	        </div>
66	      </foreignObject>
67	    );
68	  }
69	}
70	
71	const mapStateToProps = (state: KialiAppState, props: any) => {
72	  const { matrix, isComplete } = reduceMetricsStats(props.trace, state.metricsStats.data, true);
73	  return {
74	    statsMatrix: matrix,
75	    isStatsMatrixComplete: isComplete
76	  };
77	};
78	
79	const TraceLabelContainer = connect(mapStateToProps)(TraceLabel);
80	
81	export class TraceTooltip extends React.Component<HookedTooltipProps<JaegerLineInfo>> {
82	  render() {
83	    if (this.props.activePoints && this.props.activePoints.length > 0) {
84	      const trace = this.props.activePoints[0].trace;
85	      return (
86	        <HookedChartTooltip
87	          {...this.props}
88	          flyoutWidth={flyoutWidth}
89	          flyoutHeight={flyoutHeight}
90	          flyoutComponent={<ChartCursorFlyout style={{ stroke: 'none', fillOpacity: 0.6 }} />}
91	          labelComponent={<TraceLabelContainer trace={trace} />}
92	        />
93	      );
94	    }
95	    return null;
96	  }
97	}

